// Filter on lines with >3 overshoots
const items = $input.all().map(i => i.json);
const flagged = items.filter(x => x.total_overshoots > 3);

if (flagged.length === 0) {
  return [{ json: { trigger: false, reason: 'No line exceeded 3 overshoots in last 7 days' } }];
}

return flagged.map(line => ({
  json: {
    trigger: true,
    solve_id: 'SOLVE-C',
    line: line._id,
    days_with_overshoot: line.days_with_overshoot,
    total_overshoots: line.total_overshoots,
    avg_dwell_overshoots: Math.round(line.avg_dwell_overshoots * 10) / 10,
    max_dwell_overshoots: Math.round(line.max_dwell_overshoots * 10) / 10,
    recommendation: line.total_overshoots > 10
      ? 'Heroverweeg recipe-volgorde en bandsnelheid setpoints. Inspectie van proofer-01.'
      : 'Plan kleinere proofing-batches komende week. Monitor temperatuur/vocht stabiliteit.'
  }
}));
